INSERT INTO profile_scenario_responses (id, profile_id, scenario_id, response, reasoning_chain, emotional_arc, confidence, generation_run_id) VALUES
('e8193a6c-1de4-4892-9ec6-411781df6ffa', 'e0d36da4-f566-477a-aa33-6592a59ab3f7', '91c3b809-a279-4ab7-b515-fcb8e485bc0e', 'Faced with this, this profile tracks concessions explicitly and matches them one-for-one, never more, and true to form never quite escapes the first figure it heard, however arbitrary.', 'Lays out the options explicitly, assigns each a rough expected value, and picks the one that survives the numbers — distrusting any impulse that cannot be written down. The relationship and the number are both on the table at once.', 'A flash of heat that cools almost immediately, resolving into appeasement — that dissolves quickly once the ambiguity clears.', 0.67, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('7c90acc8-1e84-4380-89d2-2ae42bac0a5a', '4d953357-c647-4a74-8cd2-7a822b7b03a6', 'fba24ba2-2531-403b-b4fc-137cecbb4af5', 'Faced with this, this type stays silent past the point of discomfort, letting the other side fill the gap, and true to form discounts their own exposure to the risks they warn others about.', 'Treats the choice as a small research problem: gather the knowable facts first, model the downside, then commit only once the math stops moving. Every option here also has to survive the other side''s reaction.', 'The faintest tightening, gone as soon as it is noticed, resolving into cold calculation — that leaves no discernible trace once the moment passes.', 0.68, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('c2292ad3-c6ab-4950-98ea-381f6761bc0b', '22f18890-18a9-4e19-92a8-bc6383fced52', 'cb02b2bc-3305-47e3-8cdf-a18774fbb54d', 'Faced with this, the individual tracks concessions explicitly and matches them one-for-one, never more, and true to form expects to be the exception to a risk it can otherwise describe accurately.', 'Breaks the decision into weighted criteria before looking at gut feel, and lets the tally overrule any single strong reaction. The counterparty is reading every hesitation as information.', 'Barely a ripple of concern, resolving into stoic freeze — that resolves almost before it registers.', 0.77, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('a604fc8b-fde1-4bc2-973a-b9cfd1ec8a81', 'd4d91e49-ba54-4cf4-9c05-d98a800fa6d4', '70eba9b0-4d60-4ba0-989b-45ea303d5751', 'Faced with this, this person lets the numbers set the floor and refuses to negotiate against itself, and true to form discounts their own exposure to the risks they warn others about.', 'Builds an explicit decision matrix for a call most people would make on instinct, and defers to whichever option scores highest even if it feels wrong. Every option here also has to survive the other side''s reaction.', 'The faintest tightening, gone as soon as it is noticed, resolving into euphoric overreach — that leaves no discernible trace once the moment passes.', 0.73, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('b22ae2df-7b52-4235-8dca-8c08dc518748', 'ea15b0c1-b142-46a0-8da1-447cd6b6f58b', 'e0a56e9f-0164-401e-bc51-17dd82ec3c61', 'Faced with this, this person holds the line to their BATNA, trading patience for leverage and refusing to move first, and true to form underestimates how often an obviously right call turns out wrong.', 'Lays out the options explicitly, assigns each a rough expected value, and picks the one that survives the numbers — distrusting any impulse that cannot be written down. The counterparty is reading every hesitation as information.', 'The faintest tightening, gone as soon as it is noticed, resolving into cold calculation — that never really rises to the level of a feeling at all.', 0.89, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('3df98b9a-7dec-4544-bedf-5227294eb45a', 'b9d26c9e-d409-481c-8125-cf1c47efb885', '77ebcea6-947b-4aca-b81f-b983e67847dc', 'Faced with this, this person tracks concessions explicitly and matches them one-for-one, never more, and true to form holds their estimates with a certainty the track record does not support.', 'Walks every branch and contingency in sequence, uneasy until the residual ambiguity is as small as it can be. The relationship and the number are both on the table at once.', 'A noticeable but manageable spike of unease, resolving into defiant doubling — that dissolves quickly once the ambiguity clears.', 0.88, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('b069ad2f-446e-4aa0-8edf-8ccf7d3a61b8', '32aa67cc-a364-472d-b774-de6a72a6cefa', '73626ea5-320a-46cb-aa0b-b1de9923aa74', 'Faced with this, this person stays silent past the point of discomfort, letting the other side fill the gap, and true to form rewrites its own uncertainty out of the story after the fact.', 'Treats a rushed decision as a defect regardless of outcome, and resists pressure to shortcut the process. Every option here also has to survive the other side''s reaction.', 'The faintest tightening, gone as soon as it is noticed, resolving into cold calculation — that is essentially forgotten by the next decision.', 0.72, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
('e5b23a0d-0048-4e2f-b4d3-04ec704bb2be', 'c34abb80-6911-4f90-bda9-d0fcb7c8ab3d', '06ad9448-7dd8-450f-9946-fc3d58c4b9a2', 'Faced with this, the individual tracks concessions explicitly and matches them one-for-one, never more, and true to form measures every later offer against the opening one, not against fair value.', 'Builds an explicit decision matrix for a call most people would make on instinct, and defers to whichever option scores highest even if it feels wrong. Every option here also has to survive the other side''s reaction.', 'A flat, measured pulse with no real spike, resolving into relief capitulation — that is essentially forgotten by the next decision.', 0.7, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
