INSERT INTO profile_scenario_responses (id, profile_id, scenario_id, response, reasoning_chain, emotional_arc, confidence, generation_run_id) VALUES
('aca166c1-5bfe-43ab-ade7-46a711d38495', 'a4a2b584-a360-4e2a-97ed-bec950c1e4aa', 'e530e22f-e118-400b-99d7-0c9dc6aadef4', 'Faced with this, this profile chases the move in real time, adjusting size on gut feel as the price ticks, and true to form sells the winners early and clings to the losers for far too long.', 'Reframes inaction as patience, and patience as strategy, for as long as the situation allows. This time the variable is money moving in real time.', 'A hot flash of panic before any thought forms, resolving into anxious spiral — that keeps resurfacing in quiet moments for days afterward.', 0.52, '23f52993-d83a-4722-a8af-d91ec112c7a4'),
